import{_ as t,o as i,c as a,a7 as r}from"./chunks/framework.C5fSpjcB.js";const y=JSON.parse('{"title":"Affinity System","description":"","frontmatter":{},"headers":[],"relativePath":"en/systems/affinity.md","filePath":"en/systems/affinity.md","lastUpdated":1775394001000}'),n={name:"en/systems/affinity.md"};function o(s,e,l,d,c,h){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="affinity-system" tabindex="-1">Affinity System <a class="header-anchor" href="#affinity-system" aria-label="Permalink to &quot;Affinity System&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The affinity system allows players to build deeper bonds with characters. Raising affinity unlocks exclusive story episodes, voice lines, and stat bonuses.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>The affinity system in Morimens is called <strong>Silver Core Communication</strong> (银芯通信). Through this interface, the Keeper builds relationships with Awakeners by interacting, giving gifts, including them in battle, and completing character-specific quests.</p><p>For full details, see the <a href="./../story/silver-core.html">Silver Core Communication</a> page.</p><h2 id="affinity-levels" tabindex="-1">Affinity Levels <a class="header-anchor" href="#affinity-levels" aria-label="Permalink to &quot;Affinity Levels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Level</th><th>Unlocked Content</th></tr></thead><tbody><tr><td>1</td><td>Basic interaction dialogue</td></tr><tr><td>2</td><td>First personal story episode</td></tr><tr><td>3</td><td>New voice lines</td></tr><tr><td>4</td><td>Stat bonus (minor)</td></tr><tr><td>5</td><td>Second personal story episode</td></tr><tr><td>6</td><td>Additional voice lines</td></tr><tr><td>7</td><td>Stat bonus (moderate)</td></tr><tr><td>8</td><td>Third personal story episode</td></tr><tr><td>9</td><td>Special cosmetic content (expressions, profile items)</td></tr><tr><td>10</td><td>Final personal story episode and full stat bonus</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Exact affinity point thresholds vary by level. Higher tiers require significantly more points.</p></div><h2 id="ways-to-raise-affinity" tabindex="-1">Ways to Raise Affinity <a class="header-anchor" href="#ways-to-raise-affinity" aria-label="Permalink to &quot;Ways to Raise Affinity&quot;">​</a></h2><ul><li><strong>Gift Giving</strong> -- Give Awakeners their preferred gifts for high affinity gains. Neutral gifts grant a small amount, while disliked gifts may grant none.</li><li><strong>Interaction</strong> -- Use the Silver Core Communication interface to interact with Awakeners daily. Small daily interactions accumulate over time.</li><li><strong>Party Inclusion</strong> -- Including an Awakener in your battle party slowly builds affinity through shared combat experience.</li><li><strong>Character Quests</strong> -- Special quests tied to each Awakener&#39;s backstory. Completing them grants substantial affinity.</li></ul><h2 id="affinity-rewards" tabindex="-1">Affinity Rewards <a class="header-anchor" href="#affinity-rewards" aria-label="Permalink to &quot;Affinity Rewards&quot;">​</a></h2><p>Raising affinity grants:</p><ul><li><strong>Story Episodes</strong> -- Personal backstory chapters that reveal each Awakener&#39;s history, motivations, and secrets. These tie into the game&#39;s central theme of memory and human connection</li><li><strong>Voice Lines</strong> -- New dialogue and voice clips unlocked at various affinity milestones</li><li><strong>Stat Bonuses</strong> -- Minor to moderate stat increases for the Awakener, aiding their combat performance</li><li><strong>Cosmetics</strong> -- Special expressions, profile decorations, or other visual content</li></ul><h2 id="connection-to-lore" tabindex="-1">Connection to Lore <a class="header-anchor" href="#connection-to-lore" aria-label="Permalink to &quot;Connection to Lore&quot;">​</a></h2><p>The affinity system reflects Morimens&#39; core theme of <strong>memory and forgetting</strong>. In a world where the Erosion erases people from existence -- including all memories of them -- the bonds forged through Silver Core Communication represent an act of defiance. By remembering and connecting with Awakeners, the Keeper fights against the very force that threatens to unmake the world.</p><p>Each Awakener&#39;s personal story episodes, unlocked through rising affinity, reveal crucial lore about:</p><ul><li>The Awakener&#39;s origin and how they became an Awakened One</li><li>Their connection to the broader factions (Mythag University, Sculptors&#39; Association, Church of the Lightbearers, etc.)</li><li>Their relationship to the Erosion and the Cthulhu Mythos archetypes they embody</li><li>Hidden connections between characters that are not apparent from the main story alone</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li><strong>Prioritize your main team</strong> -- Focus affinity gains on Awakeners you use in combat to benefit from stat bonuses</li><li><strong>Check gift preferences</strong> -- Pay attention to each Awakener&#39;s personality and lore background to determine their preferred gifts</li><li><strong>Daily consistency</strong> -- Small daily interactions accumulate significantly over time</li><li><strong>Read the stories</strong> -- Character stories provide valuable lore context and make the overall narrative richer</li></ul>',20)])])}const m=t(n,[["render",o]]);export{y as __pageData,m as default};
